  ('locality-d592fc58-moex-00065', 'locality-d592fc58', 'locality-d592fc58-moex-113-d3ff7f6b', 'sub-locality-d592fc58-02', NULL, 'single_choice', '假設A只活兩期，他在這兩期的所得皆為220元，並且兩期都要消費，獲得效用為U=C0.75C0.25。', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:24+00:00", "source_pdf_sha1": "73210569d047", "answer_pdf_sha1": "27b49f81005c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "318", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "locality", "civil_category": "商業行政"}'::jsonb, NULL),
